				request.url.includes("/cdn-cgi\\")
			) {
				analytics.setData({ cdnCgiBackslashBypassUrl: request.url });
				return new TemporaryRedirectResponse(url.href);
			}

			const routeToUserWorker = async ({
				asset,
			}: {
				asset: "static_routing" | "none";
			}) => {
				if (!config.has_user_worker) {
					throw new Error(
						"Fetch for user worker without having a user worker binding"
					);
				}
				if (eyeballConfig.limitedAssetsOnly) {
					analytics.setData({ userWorkerFreeTierLimiting: true });
					return new Response(renderLimitedResponse(request), {
						status: 429,
						headers: {
							"Content-Type": "text/html",
						},
					});
				}
				analytics.setData({ dispatchtype: DISPATCH_TYPE.WORKER });
				userWorkerInvocation = true;
				return env.JAEGER.enterSpan("dispatch_worker", async (span) => {
					span.setTags({
						hasUserWorker: true,
						asset: asset,
						dispatchType: DISPATCH_TYPE.WORKER,
					});

					let shouldCheckContentType = false;
					if (url.pathname.endsWith("/_next/image")) {
						// is a next image
						const queryURLParam = url.searchParams.get("url");
						if (queryURLParam && !queryURLParam.startsWith("/")) {
							// that's a remote resource
							if (
								request.method !== "GET" ||
								request.headers.get("sec-fetch-dest") !== "image"
							) {
								// that was not loaded via a browser's <img> tag
								shouldCheckContentType = true;
								analytics.setData({ abuseMitigationURLHost: queryURLParam });
							}
							// otherwise, we're good
						}
					}

					if (url.pathname === "/_image") {
						const hrefParam = url.searchParams.get("href");
						if (
							hrefParam &&
							hrefParam.length > 2 &&
							hrefParam.startsWith("//")
						) {
							try {
								const hrefUrl = new URL("https:" + hrefParam);
								const isImageFetchDest =
									request.headers.get("sec-fetch-dest") == "image";

								if (hrefUrl.hostname !== url.hostname && !isImageFetchDest) {
									analytics.setData({ xssDetectionImageHref: hrefParam });
									return new Response("Blocked", { status: 403 });
								}
							} catch {
								console.log(`Invalid href parameter in /_image: ${hrefParam}`);
							}
						}
					}

					analytics.setData({
						timeToDispatch: performance.now() - startTimeMs,
					});

					if (shouldCheckContentType) {
						const response = await env.USER_WORKER.fetch(request);

						if (response.status !== 304 && shouldBlockContentType(response)) {
							analytics.setData({ abuseMitigationBlocked: true });
							return new Response("Blocked", { status: 403 });
						}
						return response;
					}
					return env.USER_WORKER.fetch(request);
				});
			};

			const routeToAssets = async ({
				asset,
			}: {
				asset: "static_routing" | "found" | "none";
			}) => {
				analytics.setData({ dispatchtype: DISPATCH_TYPE.ASSETS });
				return await env.JAEGER.enterSpan("dispatch_assets", async (span) => {
					span.setTags({
						hasUserWorker: config.has_user_worker,
						asset: asset,
						dispatchType: DISPATCH_TYPE.ASSETS,
					});

					analytics.setData({
						timeToDispatch: performance.now() - startTimeMs,
					});
					return env.ASSET_WORKER.fetch(request);
				});
			};

			if (config.static_routing) {
				// evaluate "exclude" rules
				const excludeRulesMatcher = generateStaticRoutingRuleMatcher(
					config.static_routing.asset_worker ?? []
				);
				if (
					excludeRulesMatcher({
						request,
					})
				) {
					// direct to asset worker
					analytics.setData({
						staticRoutingDecision: STATIC_ROUTING_DECISION.ROUTED,
					});
					return await routeToAssets({ asset: "static_routing" });
				}
				// evaluate "include" rules
				const includeRulesMatcher = generateStaticRoutingRuleMatcher(
					config.static_routing.user_worker
				);
				if (
					includeRulesMatcher({
						request,
					})
				) {
					if (!config.has_user_worker) {
						throw new Error(
							"Fetch for user worker without having a user worker binding"
						);
					}
					// direct to user worker
					analytics.setData({
						staticRoutingDecision: STATIC_ROUTING_DECISION.ROUTED,
					});
					return await routeToUserWorker({ asset: "static_routing" });
				}

				analytics.setData({
					staticRoutingDecision: hasStaticRouting
						? STATIC_ROUTING_DECISION.NOT_ROUTED
						: STATIC_ROUTING_DECISION.NOT_PROVIDED,
				});
			}

			// User's configuration indicates they want user-Worker to run ahead of any
			// assets. Do not provide any fallback logic.
			if (config.invoke_user_worker_ahead_of_assets) {
				return await routeToUserWorker({ asset: "static_routing" });
			}

			// If we have a user-Worker, but no assets, dispatch to Worker script
			// Do not pass the original request as it would consume the body
			const assetsExist = await env.ASSET_WORKER.unstable_canFetch(
				new Request(request.url, {
					headers: request.headers,
					method: request.method,
				})
			);
			if (config.has_user_worker && !assetsExist) {
				return await routeToUserWorker({ asset: "none" });
			}

			// Otherwise, we either don't have a user worker, OR we have matching assets and should fetch from the assets binding
			return await routeToAssets({ asset: assetsExist ? "found" : "none" });
		} catch (err) {
			if (userWorkerInvocation) {
				// Don't send user Worker errors to sentry; we have no way to distinguish between
				// CF errors and errors from the user's code.
				throw err;
			} else if (err instanceof Error) {
				analytics.setData({ error: err.message });
			}

			// Log to Sentry if we can
			if (sentry) {
				sentry.captureException(err);
			}
			throw err;
		} finally {
			analytics.setData({ requestTime: performance.now() - startTimeMs });
			analytics.write();
		}
	},
};

/**
 * Check if the Content Type is allowed for the the `_next/image` endpoint.
 *
 * - Content Type with multiple values should be blocked
 * - Only Image and Plain Text types are not blocked
 *
 * @param contentType The value of the Content Type header (`null` if no set)
 * @returns Whether the Content Type should be blocked
 */
function shouldBlockContentType(response: Response): boolean {
	const contentType = response.headers.get("content-type");

	if (contentType === null) {
		return true;
	}

	// Block responses with multiple Content Types.
	// https://httpwg.org/specs/rfc9110.html#field.content-type
	if (contentType.includes(",")) {
		return true;
	}

	// Allow only
	// - images (`image/...`)
	// - plain text (`text/plain`, `text/plain;charset=UTF-8`), used by Next errors
	return !(
		contentType.startsWith("image/") ||
		contentType.split(";")[0] === "text/plain"
	);
}
"],

  "sourcesContent": ["import { DurableObject } from "cloudflare:workers";
import {
	all,
	BlobStore,
	createTypedSql,
	get,
	SharedBindings,
	Timers,
} from "miniflare:shared";
import { BadRequestError, InvalidURLError, NotFoundError } from "./errors";
import { SQL_SCHEMA } from "./schemas";
import type {
	CaptionRow,
	DownloadRow,
	VideoRow,
	WatermarkRow,
} from "./schemas";
import type { BlobId, TypedSql } from "miniflare:shared";

const BLOB_NAMESPACE = "stream-data";

interface Env {
	MINIFLARE_BLOBS?: Fetcher;
	MINIFLARE_STICKY_BLOBS?: boolean;
	[SharedBindings.MAYBE_JSON_ENABLE_CONTROL_ENDPOINTS]?: boolean;
}

export class StreamObject extends DurableObject<Env> {
	readonly timers = new Timers();
	readonly #blob: BlobStore;
	readonly #db: TypedSql;
	readonly #stmts: ReturnType<typeof sqlStmts>;

	#now() {
		return new Date(this.timers.now()).toISOString();
	}

	constructor(state: DurableObjectState, env: Env) {
		super(state, env);
		const db = createTypedSql(state.storage);
		db.exec("PRAGMA foreign_keys = ON");
		db.exec(SQL_SCHEMA);
		this.#db = db;
		this.#stmts = sqlStmts(db, () => this.#now());
		const stickyBlobs = !!env.MINIFLARE_STICKY_BLOBS;
		this.#blob = new BlobStore(
			env.MINIFLARE_BLOBS as Fetcher,
			BLOB_NAMESPACE,
			stickyBlobs
		);
	}

	async createVideo(
		body: ReadableStream<Uint8Array> | null,
		params: StreamUrlUploadParams
	): Promise<VideoRow> {
		const id = crypto.randomUUID();
		const now = this.#now();

		let blobId: BlobId | null = null;
		let size = 0;

		if (body !== null) {
			// Count bytes while streaming through to blob storage
			const { readable, writable } = new TransformStream<
				Uint8Array,
				Uint8Array
			>({
				transform(chunk, controller) {
					size += chunk.byteLength;
					controller.enqueue(chunk);
				},
			});
			[blobId] = await Promise.all([
				this.#blob.put(readable),
				body.pipeTo(writable),
			]);
		}

		this.#stmts.insertVideo({
			id,
			creator: params.creator ?? null,
			meta: JSON.stringify(params.meta ?? {}),
			allowed_origins: JSON.stringify(params.allowedOrigins ?? []),
			require_signed_urls: params.requireSignedURLs ? 1 : 0,
			scheduled_deletion: params.scheduledDeletion ?? null,
			thumbnail_timestamp_pct: params.thumbnailTimestampPct ?? 0,
			created: now,
			modified: now,
			uploaded: body !== null ? now : null,
			status_state: body !== null ? "ready" : "pendingupload",
			ready_to_stream: body !== null ? 1 : 0,
			size,
			blob_id: blobId,
		});

		const row = get(this.#stmts.getVideo({ id }));
		if (row === undefined) throw new NotFoundError(`Video not found: ${id}`);
		return row;
	}

	async getVideo(id: string): Promise<VideoRow> {
		const row = get(this.#stmts.getVideo({ id }));
		if (row === undefined) throw new NotFoundError(`Video not found: ${id}`);
		return row;
	}

	async updateVideo(
		id: string,
		params: StreamUpdateVideoParams
	): Promise<VideoRow> {
		return this.#stmts.updateVideo(id, params);
	}

	async deleteVideo(id: string): Promise<void> {
		const blobIds = this.#stmts.deleteVideo(id);
		await Promise.all(blobIds.map((b) => this.#blob.delete(b)));
	}

	async listVideos(params?: StreamVideosListParams): Promise<VideoRow[]> {
		if (params?.before === undefined && params?.after === undefined) {
			if (params?.limit === undefined) {
				return all(this.#stmts.listVideos({}));
			}
			return all(this.#stmts.listVideosLimit({ limit: params.limit }));
		}

		const compToSql: Record<string, string> = {
			eq: "=",
			gt: ">",
			gte: ">=",
			lt: "<",
			lte: "<=",
		};
		const conditions: string[] = [];
		const values: (string | number)[] = [];

		if (params.before !== undefined) {
			const op = compToSql[params.beforeComp ?? "lt"];
			if (op === undefined) {
				throw new BadRequestError(
					"Invalid comparison operator: " + String(params.beforeComp)
				);
			}
			conditions.push("created " + op + " ?");
			values.push(params.before);
		}
		if (params.after !== undefined) {
			const op = compToSql[params.afterComp ?? "gte"];
			if (op === undefined) {
				throw new BadRequestError(
					"Invalid comparison operator: " + String(params.afterComp)
				);
			}
			conditions.push("created " + op + " ?");
			values.push(params.after);
		}

		values.push(params.limit ?? 1000);
		const sql =
			"SELECT * FROM _mf_stream_videos WHERE " +
			conditions.join(" AND ") +
			" ORDER BY created DESC LIMIT ?";
		return Array.from(this.#db.exec<VideoRow>(sql, ...values));
	}

	async generateToken(id: string): Promise<string> {
		const row = get(this.#stmts.getVideo({ id }));
		if (row === undefined) throw new NotFoundError(`Video not found: ${id}`);

		const payload = {
			sub: id,
			kid: "local-mode-key",
			exp: Math.floor(this.timers.now() / 1000) + 6 * 60 * 60,
		};
		return btoa(JSON.stringify(payload));
	}

	async generateCaption(
		videoId: string,
		language: string
	): Promise<CaptionRow> {
		const video = get(this.#stmts.getVideo({ id: videoId }));
		if (video === undefined)
			throw new NotFoundError(`Video not found: ${videoId}`);

		const label =
			new Intl.DisplayNames(["en"], { type: "language" }).of(language) ??
			language;

		// Delete old blob if caption already exists
		const existing = get(
			this.#stmts.getCaption({ video_id: videoId, language })
		);
		if (existing?.blob_id !== undefined && existing.blob_id !== null) {
			await this.#blob.delete(existing.blob_id);
		}

		this.#stmts.upsertCaption({
			video_id: videoId,
			language,
			generated: 1,
			label,
			status: "ready",
			blob_id: null,
		});

		const row = get(this.#stmts.getCaption({ video_id: videoId, language }));
		if (row === undefined)
			throw new NotFoundError(`Caption not found: ${videoId}/${language}`);
		return row;
	}

	async uploadCaption(
		videoId: string,
		language: string,
		input: ReadableStream
	): Promise<CaptionRow> {
		const video = get(this.#stmts.getVideo({ id: videoId }));
		if (video === undefined)
			throw new NotFoundError(`Video not found: ${videoId}`);

		const label =
			new Intl.DisplayNames(["en"], { type: "language" }).of(language) ??
			language;

		// Delete old blob if caption already exists
		const existing = get(
			this.#stmts.getCaption({ video_id: videoId, language })
		);
		if (existing?.blob_id !== undefined && existing.blob_id !== null) {
			await this.#blob.delete(existing.blob_id);
		}

		const blobId = await this.#blob.put(input);

		this.#stmts.upsertCaption({
			video_id: videoId,
			language,
			generated: 0,
			label,
			status: "ready",
			blob_id: blobId,
		});

		const row = get(this.#stmts.getCaption({ video_id: videoId, language }));
		if (row === undefined)
			throw new NotFoundError(`Caption not found: ${videoId}/${language}`);
		return row;
	}

	async listCaptions(
		videoId: string,
		language?: string
	): Promise<CaptionRow[]> {
		const video = get(this.#stmts.getVideo({ id: videoId }));
		if (video === undefined)
			throw new NotFoundError(`Video not found: ${videoId}`);

		if (language !== undefined) {
			const row = get(this.#stmts.getCaption({ video_id: videoId, language }));
			return row !== undefined ? [row] : [];
		}
		return all(this.#stmts.listCaptionsByVideo({ video_id: videoId }));
	}

	async deleteCaption(videoId: string, language: string): Promise<void> {
		const deleted = get(
			this.#stmts.deleteCaption({ video_id: videoId, language })
		);
		if (deleted === undefined) {
			throw new NotFoundError(`Caption not found: ${videoId}/${language}`);
		}
		if (deleted.blob_id !== null) {
			await this.#blob.delete(deleted.blob_id);
		}
	}

	async createWatermarkFromUrl(
		url: string,
		params: StreamWatermarkCreateParams
	): Promise<WatermarkRow> {
		const response = await fetch(url);
		if (!response.ok || response.body === null) {
			throw new InvalidURLError(
				`Failed to fetch watermark from URL: ${response.status} ${response.statusText}`
			);
		}

		return this.createWatermarkFromBody(
			await response.arrayBuffer(),
			url,
			params
		);
	}

	async createWatermarkFromBody(
		buffer: ArrayBuffer,
		downloadedFrom: string | null,
		params: StreamWatermarkCreateParams
	): Promise<WatermarkRow> {
		const size = buffer.byteLength;
		const blobId = await this.#blob.put(
			new Response(buffer).body as ReadableStream<Uint8Array>
		);

		const id = crypto.randomUUID();
		const now = this.#now();

		this.#stmts.insertWatermark({
			id,
			name: params.name ?? "",
			size,
			created: now,
			downloaded_from: downloadedFrom,
			opacity: params.opacity ?? 1.0,
			padding: params.padding ?? 0.05,
			scale: params.scale ?? 0.15,
			position: params.position ?? "upperRight",
			blob_id: blobId,
		});

		const row = get(this.#stmts.getWatermark({ id }));
		if (row === undefined)
			throw new NotFoundError(`Watermark not found: ${id}`);
		return row;
	}

	async getWatermark(id: string): Promise<WatermarkRow> {
		const row = get(this.#stmts.getWatermark({ id }));
		if (row === undefined)
			throw new NotFoundError(`Watermark not found: ${id}`);
		return row;
	}

	async listWatermarks(): Promise<WatermarkRow[]> {
		return all(this.#stmts.listWatermarks({}));
	}

	async deleteWatermark(id: string): Promise<void> {
		const deleted = get(this.#stmts.deleteWatermark({ id }));
		if (deleted === undefined)
			throw new NotFoundError(`Watermark not found: ${id}`);
		if (deleted.blob_id !== null) {
			await this.#blob.delete(deleted.blob_id);
		}
	}

	async generateDownload(
		videoId: string,
		downloadType: StreamDownloadType = "default"
	): Promise<DownloadRow[]> {
		const video = get(this.#stmts.getVideo({ id: videoId }));
		if (video === undefined)
			throw new NotFoundError(`Video not found: ${videoId}`);

		this.#stmts.upsertDownload({
			video_id: videoId,
			download_type: downloadType,
			status: "ready",
			percent_complete: 100.0,
		});

		return all(this.#stmts.listDownloads({ video_id: videoId }));
	}

	async listDownloads(videoId: string): Promise<DownloadRow[]> {
		const video = get(this.#stmts.getVideo({ id: videoId }));
		if (video === undefined)
			throw new NotFoundError(`Video not found: ${videoId}`);
		return all(this.#stmts.listDownloads({ video_id: videoId }));
	}

	async deleteDownload(
		videoId: string,
		downloadType: StreamDownloadType = "default"
	): Promise<void> {
		const deleted = get(
			this.#stmts.deleteDownload({
				video_id: videoId,
				download_type: downloadType,
			})
		);
		if (deleted === undefined) {
			throw new NotFoundError(`Download not found: ${videoId}/${downloadType}`);
		}
	}

	async getVideoBlob(
		videoId: string
	): Promise<{ stream: ReadableStream<Uint8Array>; size: number } | null> {
		const row = get(this.#stmts.getVideo({ id: videoId }));
		if (row === undefined || row.blob_id === null) {
			return null;
		}
		const stream = await this.#blob.get(row.blob_id);
		if (stream === null) {
			return null;
		}
		return { stream, size: row.size };
	}

	async fetch(
		req: Request<
			unknown,
			{ miniflare?: { controlOp?: { name: string; args?: unknown[] } } }
		>
	) {
		if (this.env[SharedBindings.MAYBE_JSON_ENABLE_CONTROL_ENDPOINTS] === true) {
			const controlOp = req.cf?.miniflare?.controlOp;
			if (controlOp !== undefined) {
				const args = controlOp.args ?? [];
				switch (controlOp.name) {
					case "enableFakeTimers":
						await this.timers.enableFakeTimers(args[0] as number);
						return Response.json(null);
					case "disableFakeTimers":
						await this.timers.disableFakeTimers();
						return Response.json(null);
					case "advanceFakeTime":
						await this.timers.advanceFakeTime(args[0] as number);
						return Response.json(null);
					case "waitForFakeTasks":
						await this.timers.waitForFakeTasks();
						return Response.json(null);
				}
			}
		}

		return new Response(null, { status: 404 });
	}
}

// Helper functions to return all db statements
function sqlStmts(db: TypedSql, now: () => string) {
	// Videos

	const stmtGetVideo = db.stmt<Pick<VideoRow, "id">, VideoRow>(
		"SELECT * FROM _mf_stream_videos WHERE id = :id"
	);

	const stmtInsertVideo = db.stmt<
		Pick<
			VideoRow,
			| "id"
			| "creator"
			| "meta"
			| "allowed_origins"
			| "require_signed_urls"
			| "scheduled_deletion"
			| "thumbnail_timestamp_pct"
			| "created"
			| "modified"
			| "uploaded"
			| "status_state"
			| "ready_to_stream"
			| "size"
			| "blob_id"
		>
	>(`INSERT INTO _mf_stream_videos (
		id, creator, meta, allowed_origins, require_signed_urls,
		scheduled_deletion, thumbnail_timestamp_pct, created, modified,
		uploaded, status_state, ready_to_stream, size, blob_id
	) VALUES (
		:id, :creator, :meta, :allowed_origins, :require_signed_urls,
		:scheduled_deletion, :thumbnail_timestamp_pct, :created, :modified,
		:uploaded, :status_state, :ready_to_stream, :size, :blob_id
	)`);

	const stmtUpdateVideo = db.stmt<
		Pick<
			VideoRow,
			| "id"
			| "modified"
			| "creator"
			| "meta"
			| "allowed_origins"
			| "require_signed_urls"
			| "scheduled_deletion"
			| "thumbnail_timestamp_pct"
			| "max_duration_seconds"
		>
	>(`UPDATE _mf_stream_videos SET
		modified = :modified,
		creator = :creator,
		meta = :meta,
		allowed_origins = :allowed_origins,
		require_signed_urls = :require_signed_urls,
		scheduled_deletion = :scheduled_deletion,
		thumbnail_timestamp_pct = :thumbnail_timestamp_pct,
		max_duration_seconds = :max_duration_seconds
	WHERE id = :id`);

	const stmtGetVideoCaptionBlobs = db.stmt<
		Pick<VideoRow, "id">,
		Pick<CaptionRow, "blob_id">
	>("SELECT blob_id FROM _mf_stream_captions WHERE video_id = :id");

	const stmtDeleteVideoDownloads = db.stmt<Pick<VideoRow, "id">>(
		"DELETE FROM _mf_stream_downloads WHERE video_id = :id"
	);

	const stmtDeleteVideo = db.stmt<
		Pick<VideoRow, "id">,
		Pick<VideoRow, "blob_id">
	>("DELETE FROM _mf_stream_videos WHERE id = :id RETURNING blob_id");

	const stmtListVideos = db.stmt<Record<string, never>, VideoRow>(
		"SELECT * FROM _mf_stream_videos ORDER BY created DESC"
	);

	const stmtListVideosLimit = db.stmt<{ limit: number }, VideoRow>(
		"SELECT * FROM _mf_stream_videos ORDER BY created DESC LIMIT :limit"
	);

	// Captions

	const stmtGetCaption = db.stmt<
		Pick<CaptionRow, "video_id" | "language">,
		CaptionRow
	>(
