	do(
		name: string,
		config: WorkflowStepConfig,
		callback: (ctx: WorkflowStepContext) => Promise<unknown>
	): Promise<unknown>;

	async do<T>(
		name: string,
		configOrCallback:
			| WorkflowStepConfig
			| ((ctx: WorkflowStepContext) => Promise<T>),
		callback?: (ctx: WorkflowStepContext) => Promise<T>
	): Promise<unknown | void | undefined> {
